#include <iostream>
#include <iomanip>
using namespace std;

int main() {
    int N;
    cin >> N;

    int grid[10][10];
    int num = N * N;

    for (int i = 0; i < N; i++) {
        if (i % 2 == 0) {
            // Even rows (0-indexed): right to left
            for (int j = N - 1; j >= 0; j--) {
                grid[i][j] = num--;
            }
        } else {
            // Odd rows: left to right
            for (int j = 0; j < N; j++) {
                grid[i][j] = num--;
            }
        }
    }

    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            cout << setw(3) << grid[i][j];
        }
        cout << "\n";
    }

    return 0;
}
